UPDATE sensor
SET x = #{x}, y = #{y}, installation_height = #{installationHeight},
    effective_range = #{effectiveRange}, detection_range = #{detectionRange},
    install_remark = #{installRemark}, priority = #{priority}, risk = #{risk},
    type = #{type}, mode = #{mode}, last_sample_time = #{lastSampleTime}
WHERE id = #{id}
